        const chain = new Set();
        let current = panel;

        while (current) {
            chain.add(current);

            const ownerTrigger = current._ownerTrigger || null;
            current = ownerTrigger ? ownerTrigger.closest('.tta-hover-panel') : null;
        }

        return chain;
    }

    function isDescendantPanel(candidatePanel, ancestorPanel) {
        let current = candidatePanel;

        while (current) {
            if (current === ancestorPanel) {
                return true;
            }

            const ownerTrigger = current._ownerTrigger || null;
            current = ownerTrigger ? ownerTrigger.closest('.tta-hover-panel') : null;
        }

        return false;
    }

    function hideUnrelatedPanels(currentPanel) {
        const keepOpen = getPanelChain(currentPanel);

        Object.values(panelByTriggerClass).forEach(panel => {
            if (!keepOpen.has(panel)) {
                panel.classList.remove('active');
            }
        });
    }

    function isHoveringPanelTree(rootPanel) {
        if (!rootPanel) return false;

        if (rootPanel.matches(':hover')) {
            return true;
        }

        if (rootPanel._ownerTrigger && rootPanel._ownerTrigger.matches(':hover')) {
            return true;
        }

        return Array.from(panels).some(panel => {
            return (
                panel !== rootPanel &&
                panel.classList.contains('active') &&
                isDescendantPanel(panel, rootPanel) &&
                (
                    panel.matches(':hover') ||
                    (panel._ownerTrigger && panel._ownerTrigger.matches(':hover'))
                )
            );
        });
