                // Also close descendants of this panel
                Array.from(panels).forEach(otherPanel => {
                    if (
                        otherPanel !== panel &&
                        otherPanel.classList.contains('active') &&
                        isDescendantPanel(otherPanel, panel)
                    ) {
                        otherPanel.classList.remove('active');
                    }
