    document.addEventListener("DOMContentLoaded", function () {

        const subpanels = document.querySelectorAll('.tta-hover-subpanel[data-trigger-class]');
        if (!subpanels.length) return;

        const subpanelByTriggerClass = {};
        let activeTrigger = null;
        let hideTimer = null;

        subpanels.forEach(subpanel => {
            const cls = subpanel.dataset.triggerClass;
            if (cls) {
                subpanelByTriggerClass[cls] = subpanel;
            }
        });

        function hideAllSubpanels() {
            Object.values(subpanelByTriggerClass).forEach(subpanel => {
                subpanel.classList.remove('active');
            });
            activeTrigger = null;
        }

        function scheduleHide(subpanel, trigger) {
            clearTimeout(hideTimer);
            hideTimer = setTimeout(() => {
                const hoveringTrigger = trigger && trigger.matches(':hover');
                const hoveringSubpanel = subpanel && subpanel.matches(':hover');

                if (!hoveringTrigger && !hoveringSubpanel) {
                    subpanel.classList.remove('active');

                    if (activeTrigger === trigger) {
                        activeTrigger = null;
                    }
                }
            }, 120);
        }

        function cancelHide() {
            clearTimeout(hideTimer);
        }

        Object.keys(subpanelByTriggerClass).forEach(triggerClass => {
            const subpanel = subpanelByTriggerClass[triggerClass];
            const triggers = document.querySelectorAll('.' + triggerClass);

            triggers.forEach(trigger => {
                trigger.addEventListener('mouseenter', () => {
                    const rect = trigger.getBoundingClientRect();
                    const gap = 12;

                    cancelHide();
                    activeTrigger = trigger;

                    hideAllSubpanels();

                    activeTrigger = trigger;

                    // Position subpanel to the right of the trigger
                    subpanel.style.left = (rect.right + window.scrollX + gap) + 'px';
                    subpanel.style.top  = (rect.top + window.scrollY) + 'px';

                    subpanel.classList.add('active');
                });

                trigger.addEventListener('mouseleave', () => {
                    scheduleHide(subpanel, trigger);
                });
            });

            subpanel.addEventListener('mouseenter', () => {
                cancelHide();
            });

            subpanel.addEventListener('mouseleave', () => {
                scheduleHide(subpanel, activeTrigger);
            });
        });
    });
    </script>
